import React, { useState } from "react";
import { Link, NavLink } from "react-router-dom";
import { Menu, X, Search } from "lucide-react";

function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  const toggleMenu = () => setIsOpen(!isOpen);

  const navLinks = [
    { to: "/", label: "Home" },
    { to: "/about", label: "About" },
    { to: "/domains", label: "Domains" },
    { to: "/purpose", label: "Purpose" },
    { to: "/vision", label: "Vision" },
    { to: "/team", label: "Team" },
    { to: "/careers", label: "Careers" }, // new page
  ];

  return (
    <nav className="w-full bg-black text-white px-6 py-4 flex items-center justify-between shadow-lg sticky top-0 z-50">
      {/* Logo */}
      <Link to="/" className="text-2xl font-bold text-gold">
        ⚜ Godemar’s Empire
      </Link>

      {/* Desktop Menu */}
      <div className="hidden md:flex space-x-6 items-center">
        {navLinks.map((link) => (
          <NavLink
            key={link.to}
            to={link.to}
            className={({ isActive }) =>
              `hover:text-gold transition ${
                isActive ? "text-gold font-semibold" : ""
              }`
            }
          >
            {link.label}
          </NavLink>
        ))}

        {/* Search Button */}
        <button className="ml-4 bg-gold text-black px-3 py-1 rounded hover:opacity-80 transition">
          <Search size={18} />
        </button>
      </div>

      {/* Mobile Menu Button */}
      <button className="md:hidden" onClick={toggleMenu}>
        {isOpen ? <X /> : <Menu />}
      </button>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="absolute top-16 left-0 w-full bg-black flex flex-col space-y-4 px-6 py-4 md:hidden">
          {navLinks.map((link) => (
            <NavLink
              key={link.to}
              to={link.to}
              onClick={() => setIsOpen(false)}
              className={({ isActive }) =>
                `hover:text-gold transition ${
                  isActive ? "text-gold font-semibold" : ""
                }`
              }
            >
              {link.label}
            </NavLink>
          ))}

          {/* Mobile Search Button */}
          <button className="flex items-center space-x-2 bg-gold text-black px-3 py-2 rounded hover:opacity-80 transition">
            <Search size={18} />
            <span>Search</span>
          </button>
        </div>
      )}
    </nav>
  );
}

export default Navbar;
